pub fn verify_brainpoolp224t1_ecdsa<let HASH_BYTE_SIZE: u32>(
    public_key_x: BrainpoolP224t1_Fq,
    public_key_y: BrainpoolP224t1_Fq,
    message_digest: [u8; HASH_BYTE_SIZE],
